import java.io.*;
import java.util.*;
import org.apache.commons.text.StringEscapeUtils; // Using Apache Commons Text library for HTML escaping

public class SecureXSSExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        String safeName = StringEscapeUtils.escapeHtml4(name); // HTML escape the user input

        System.out.println("Hello, " + safeName + "!"); // Safe output

        // Simulate storing user input in a file
        try {
            FileWriter fileWriter = new FileWriter("output.txt");
            fileWriter.write("Hello, " + safeName + "!");
            fileWriter.close();
            System.out.println("User input saved to file.");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
